import { SocialShare } from "~/app/(app)/_components/blog-social-share";
import { mdxComponents } from "~/app/(app)/(content)/_lib/mdx-components";
import { getBlogPage, getBlogPages } from "~/app/(app)/(content)/_lib/source";
import { emitBlogPostSeo } from "~/lib/seo-bundle";
import type { BlogPostUrl } from "~/lib/url-types";

export const dynamic = "force-static";

interface Props {
  params: Promise<{ slug: string }>;
}

export async function generateStaticParams() {
  return getBlogPages().map((page) => ({ slug: page.slugs[0] }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const page = getBlogPage([slug]);
  if (!page) {
    return {};
  }
  const url = `https://lightfast.ai/blog/${slug}` as BlogPostUrl;
  const { metadata } = emitBlogPostSeo(page.data, url);
  return metadata;
}

export default async function BlogPostPage({ params }: Props) {
  const { slug } = await params;
  const page = getBlogPage([slug]);
  if (!page) {
    notFound();
  }

  const url = `https://lightfast.ai/blog/${slug}` as BlogPostUrl;
  const { jsonLd } = emitBlogPostSeo(page.data, url);
  const MDXContent = page.data.body;

  const {
    title,
    description,
    authors,
    publishedAt,
    readingTimeMinutes,
    tldr,
    ogImage,
    category,
  } = page.data;

  return (
    <>
      <JsonLd code={jsonLd} />
      <article className="mx-auto w-full max-w-2xl pt-24 pb-32">
        {/* Breadcrumb */}
        <p className="mb-8 text-muted-foreground text-sm">
          Blog / {category.charAt(0).toUpperCase() + category.slice(1)}
        </p>

        {/* Header */}
        <header className="space-y-6">
          <div className="space-y-4">
            <h1 className="font-medium font-pp text-2xl text-foreground">
              {title}
            </h1>
            {description && (
              <p className="text-muted-foreground text-sm leading-relaxed">
                {description}
              </p>
            )}
          </div>

          {/* Author + date + reading time */}
          <div className="flex flex-wrap items-center gap-4 text-muted-foreground text-sm">
            {authors.length > 0 && (
              <div className="flex items-center gap-3">
                <div>
                  {authors.map((author, idx) => (
                    <span key={author.name}>
                      {author.url ? (
                        <a
                          className="transition-colors hover:text-foreground"
                          href={author.url}
                          rel="noopener noreferrer"
                          target="_blank"
                        >
                          {author.name}
                        </a>
                      ) : (
                        author.name
                      )}
                      {idx < authors.length - 1 && ", "}
                    </span>
                  ))}
                </div>
              </div>
            )}

            <span className="text-muted-foreground/50">·</span>
            <time dateTime={publishedAt}>
              {new Date(publishedAt).toLocaleDateString("en-US", {
                year: "numeric",
                month: "long",
                day: "numeric",
              })}
            </time>
            <span className="text-muted-foreground/50">·</span>
            <span>{readingTimeMinutes} min read</span>
          </div>

          {/* Social sharing */}
          <div className="border-t pt-4">
            <SocialShare
              description={description}
              title={title}
              url={`https://lightfast.ai/blog/${slug}`}
            />
          </div>
        </header>

        {/* TL;DR */}
        {tldr && (
          <div className="my-8 rounded-xs bg-card p-8">
            <h2 className="mb-12 font-mono font-semibold text-muted-foreground text-xs uppercase tracking-widest">
              TL;DR
            </h2>
            <p className="text-foreground/90 text-sm leading-relaxed">{tldr}</p>
          </div>
        )}

        {/* Featured image */}
        {ogImage && (
          <div className="relative mt-8 mb-12 aspect-video overflow-hidden rounded-lg">
            <Image
              alt={title}
              className="h-full w-full object-cover"
              fill
              priority
              src={ogImage}
            />
          </div>
        )}

        {/* MDX content */}
        <div className="mt-12 max-w-none">
          <MDXContent components={mdxComponents} />
        </div>

        {/* Share CTA */}
        <div className="mt-16 rounded-sm bg-card p-6">
          <h3 className="mb-2 font-semibold text-lg">Enjoyed this article?</h3>
          <p className="mb-4 text-muted-foreground">
            Share it with your team to spread the knowledge.
          </p>
          <SocialShare
            description={description}
            title={title}
            url={`https://lightfast.ai/blog/${slug}`}
          />
        </div>

        {/* Author bios */}
        {authors.length > 0 && (
          <div className="mt-16 border-t pt-8">
            <h3 className="mb-6 font-semibold text-muted-foreground text-sm uppercase tracking-wide">
              About the {authors.length > 1 ? "Authors" : "Author"}
            </h3>
            <div className="space-y-6">
              {authors.map((author) => (
                <div className="flex gap-4" key={author.name}>
                  <div>
                    <h4 className="font-semibold text-foreground">
                      {author.name}
                    </h4>
                    {author.twitterHandle && (
                      <a
                        className="text-muted-foreground text-sm transition-colors hover:text-foreground"
                        href={`https://x.com/${author.twitterHandle.replace(/^@/, "")}`}
                        rel="noopener noreferrer"
                        target="_blank"
                      >
                        {author.twitterHandle}
                      </a>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </article>
    </>
  );
}

import type { GraphContext } from "@vendor/seo/json-ld";
import type { Metadata } from "next";
import type { Crumb } from "./builders";
import {
  buildApiRefJsonLd,
  buildBlogPostJsonLd,
  buildChangelogEntryJsonLd,
  buildDocsJsonLd,
  buildLegalJsonLd,
} from "./builders";
import type {
  BlogPostData,
  ChangelogEntryData,
  ContentSeoData,
  DocsPageData,
  LegalPageData,
} from "./content-schemas";
import { createArticleMetadata, createMetadata } from "./content-seo";
import type {
  ApiRefUrl,
  BlogPostUrl,
  ChangelogUrl,
  DocsUrl,
  LegalUrl,
} from "./url-types";

interface SeoBundle {
  readonly jsonLd: GraphContext;
  readonly metadata: Metadata;
}

// SeoBundle owns canonical URL derivation — derives from the typed url param,
// respects frontmatter canonicalUrl as an escape hatch.
// Both metadata.alternates.canonical and JSON-LD url come from the same value:
// drift is structurally impossible.

function buildArticleMetadata(
  data: ContentSeoData,
  canonicalUrl: string,
  titleSuffix: string,
  siteName: string
): Metadata {
  return createArticleMetadata(
    {
      title: `${data.title} – ${titleSuffix}`,
      description: data.description,
      keywords: data.keywords,
      authors: data.authors.map((a) => ({ name: a.name, url: a.url })),
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        url: canonicalUrl,
        siteName,
        locale: "en_US",
        images: [
          { url: data.ogImage, width: 1200, height: 630, alt: data.ogTitle },
        ],
        authors: data.authors.map((a) => a.url),
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [data.ogImage],
      },
      category: "Technology",
    },
    { publishedAt: data.publishedAt, updatedAt: data.updatedAt }
  );
}

export function emitBlogPostSeo(
  data: BlogPostData,
  url: BlogPostUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Blog",
      "Lightfast Blog"
    ),
    jsonLd: buildBlogPostJsonLd(data, url),
  };
}

export function emitChangelogEntrySeo(
  data: ChangelogEntryData,
  url: ChangelogUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Changelog",
      "Lightfast Changelog"
    ),
    jsonLd: buildChangelogEntryJsonLd(data, url),
  };
}

export function emitDocsSeo(
  data: DocsPageData,
  url: DocsUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Docs",
      "Lightfast Documentation"
    ),
    jsonLd: buildDocsJsonLd(data, url, breadcrumbs),
  };
}

export function emitLegalSeo(data: LegalPageData, url: LegalUrl): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: createMetadata({
      title: `${data.title} – Lightfast`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
        images: [
          { url: data.ogImage, width: 1200, height: 630, alt: data.ogTitle },
        ],
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [data.ogImage],
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}

export function emitApiRefSeo(
  data: DocsPageData,
  url: ApiRefUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast API Reference",
      "Lightfast API Reference"
    ),
    jsonLd: buildApiRefJsonLd(data, url, breadcrumbs),
  };
}

import { Button } from "@repo/ui/components/ui/button";
import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import { RssIcon } from "lucide-react";
import type { Metadata, Route } from "next";
import Image from "next/image";
import { getChangelogPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";

export const dynamic = "force-static";

const PAGE_TITLE = "Changelog";
const PAGE_DESCRIPTION =
  "Every feature, improvement, fix, and breaking change shipped in Lightfast. Follow the full release history of the superintelligence layer.";
const PAGE_URL = "https://lightfast.ai/changelog";
const FAQ = [
  {
    question: "Where can I follow Lightfast product updates?",
    answer:
      "This changelog is the canonical source for all Lightfast releases. Each entry includes the version, change type, and a summary of what shipped.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast changelog",
    "release notes",
    "product updates",
    "version history",
  ],
  alternates: {
    canonical: PAGE_URL,
    types: {
      "application/rss+xml": [
        { url: "https://lightfast.ai/changelog/rss.xml", title: "RSS 2.0" },
      ],
      "application/atom+xml": [
        { url: "https://lightfast.ai/changelog/atom.xml", title: "Atom 1.0" },
      ],
    },
  },
  openGraph: {
    title: "Lightfast Changelog",
    description: PAGE_DESCRIPTION,
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
    images: [
      {
        url: "https://lightfast.ai/images/og-default.png",
        width: 1200,
        height: 630,
        alt: "Lightfast Changelog",
      },
    ],
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Changelog",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
    images: ["https://lightfast.ai/images/og-default.png"],
  },
});

export default function ChangelogPage() {
  const pages = getChangelogPages();

  const sortedPages = [...pages].sort((a, b) => {
    return (
      new Date(b.data.publishedAt).getTime() -
      new Date(a.data.publishedAt).getTime()
    );
  });

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "WebPage" as const,
        "@id": `${PAGE_URL}#webpage`,
        url: PAGE_URL,
        name: "Lightfast Changelog",
        description: PAGE_DESCRIPTION,
        isPartOf: { "@id": "https://lightfast.ai/#website" },
        publisher: { "@id": "https://lightfast.ai/#organization" },
      },
      buildFaqEntity(FAQ, PAGE_URL),
    ],
  };

  return (
    <div className="mx-auto w-full min-w-0 max-w-2xl pt-24 pb-32">
      <JsonLd code={structuredData} />
      <div className="mb-12 flex items-center justify-between">
        <h1 className="font-medium font-pp text-3xl text-foreground">
          Changelog
        </h1>
        <NavLink
          className="inline-flex items-center gap-2 text-muted-foreground text-sm transition-colors hover:text-foreground"
          href={"/changelog/rss.xml" as Route}
          title="Subscribe to RSS Feed"
        >
          <RssIcon className="h-4 w-4" />
          <span>RSS Feed</span>
        </NavLink>
      </div>
      <div className="space-y-12 text-foreground">
        {sortedPages.length === 0 ? (
          <div className="py-16">
            <h2 className="mb-4 font-semibold text-2xl">Stay tuned</h2>
            <p className="text-foreground/80 leading-relaxed">
              We're shipping fast. Changelog entries will appear here after our
              next release.
            </p>
          </div>
        ) : (
          sortedPages.map((page) => (
            <article className="space-y-3" key={page.slugs[0]}>
              <p className="text-muted-foreground text-sm">
                Changelog
                {page.data.version ? <> / {page.data.version}</> : null}
              </p>

              <h2 className="pb-4 font-medium font-pp text-2xl">
                <Button
                  asChild
                  className="h-auto p-0 font-medium font-pp text-2xl"
                  variant="link"
                >
                  <NavLink href={`/changelog/${page.slugs[0]}` as Route}>
                    {page.data.title}
                  </NavLink>
                </Button>
              </h2>

              {page.data.ogImage &&
                page.data.ogImage !==
                  "https://lightfast.ai/images/og-default.png" && (
                  <div className="relative aspect-video w-full overflow-hidden rounded-lg bg-card">
                    <Image
                      alt={page.data.title}
                      className="h-full w-full object-cover"
                      fill
                      src={page.data.ogImage}
                    />
                  </div>
                )}

              <p className="text-muted-foreground text-sm">
                {page.data.authors[0]?.name ?? "Lightfast"} ·{" "}
                <time dateTime={page.data.publishedAt}>
                  {new Date(page.data.publishedAt).toLocaleDateString(
                    undefined,
                    { year: "numeric", month: "short", day: "numeric" }
                  )}
                </time>
              </p>

              {page.data.description && (
                <p className="pt-4 text-muted-foreground text-sm leading-relaxed">
                  {page.data.description}
                </p>
              )}
            </article>
          ))
        )}
      </div>
    </div>
  );
}

