import { Feed } from "feed";
import { getChangelogPages } from "~/app/(app)/(content)/_lib/source";

export function generateChangelogFeed(): Feed {
  const baseUrl = "https://lightfast.ai";
  const buildDate = new Date();

  const feed = new Feed({
    title: "Lightfast Changelog",
    description:
      "Product updates, new features, and improvements from Lightfast — surfaces decisions across your tools",
    id: `${baseUrl}/changelog`,
    link: `${baseUrl}/changelog`,
    language: "en",
    image: `${baseUrl}/android-chrome-512x512.png`,
    favicon: `${baseUrl}/favicon.ico`,
    copyright: `All rights reserved ${buildDate.getFullYear()}, Lightfast`,
    updated: buildDate,
    generator: "Lightfast Changelog Generator",
    feedLinks: {
      rss: `${baseUrl}/changelog/rss.xml`,
      atom: `${baseUrl}/changelog/atom.xml`,
    },
    author: {
      name: "Lightfast",
      email: "hello@lightfast.ai",
      link: baseUrl,
    },
  });

  const pages = getChangelogPages();

  const sortedPages = [...pages]
    .sort(
      (a, b) =>
        new Date(b.data.publishedAt).getTime() -
        new Date(a.data.publishedAt).getTime()
    )
    .slice(0, 50);

  for (const page of sortedPages) {
    const url = `${baseUrl}/changelog/${page.slugs[0]}`;
    feed.addItem({
      title: page.data.title,
      id: url,
      link: url,
      description: page.data.description,
      date: new Date(page.data.publishedAt),
      image: page.data.ogImage,
    });
  }

  return feed;
}

import type { BlogPosting, GraphContext } from "@vendor/seo/json-ld";
import type { BlogCategory, BlogPostData } from "~/lib/content-schemas";
import type { BlogPostUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

// Exhaustive mapping — adding a new BlogCategory errors here until handled
const ARTICLE_SECTIONS: Record<BlogCategory, string> = {
  engineering: "Engineering",
  product: "Product",
  company: "Company",
  tutorial: "Tutorial",
  research: "Research",
};

function buildBlogPostEntity(
  data: BlogPostData
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: data.ogImage,
      width: "1200",
      height: "630",
    },
    keywords: data.keywords.join(", "),
    articleSection: ARTICLE_SECTIONS[data.category],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildBlogPostJsonLd(
  data: BlogPostData,
  url: BlogPostUrl
): GraphContext {
  const entity = buildBlogPostEntity(data);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#article`, url },
      ...(data.faq.length > 0 ? [buildFaqEntity(data.faq, url)] : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Blog", url: "https://lightfast.ai/blog" },
        { name: data.title, url },
      ]),
    ],
  };
}

import type { BlogPosting, GraphContext } from "@vendor/seo/json-ld";
import type { ChangelogEntryData, ChangelogType } from "~/lib/content-schemas";
import type { ChangelogUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

// Exhaustive mapping — adding a new ChangelogType errors here until handled
const CHANGELOG_SECTIONS: Record<ChangelogType, string> = {
  feature: "Changelog / Feature",
  improvement: "Changelog / Improvement",
  fix: "Changelog / Fix",
  breaking: "Changelog / Breaking Change",
};

function buildChangelogEntryEntity(
  data: ChangelogEntryData
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: data.ogImage,
      width: "1200",
      height: "630",
    },
    keywords: [...data.keywords, data.version, data.type].join(", "),
    articleSection: CHANGELOG_SECTIONS[data.type],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildChangelogEntryJsonLd(
  data: ChangelogEntryData,
  url: ChangelogUrl
): GraphContext {
  const entity = buildChangelogEntryEntity(data);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#article`, url },
      ...(data.faq.length > 0 ? [buildFaqEntity(data.faq, url)] : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Changelog", url: "https://lightfast.ai/changelog" },
        { name: data.title, url },
      ]),
    ],
  };
}

