import { ContentLayout } from "@repo/og";
import { OG_HEIGHT, OG_WIDTH } from "@repo/og/brand";
import { ImageResponse } from "next/og";
import { getChangelogPage } from "~/app/(app)/(content)/_lib/source";
import { loadOGFonts } from "~/lib/og-fonts";

export const runtime = "nodejs";
export const alt = "Lightfast Changelog Entry";
export const size = { width: OG_WIDTH, height: OG_HEIGHT };
export const contentType = "image/png";

export default async function Image({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const page = getChangelogPage([slug]);
  const fonts = await loadOGFonts();

  if (!page) {
    return new ImageResponse(<div>Not Found</div>, { ...size });
  }

  const { title, description, publishedAt } = page.data;

  return new ImageResponse(
    <ContentLayout
      category="Changelog"
      date={new Date(publishedAt).toLocaleDateString("en-US", {
        year: "numeric",
        month: "long",
        day: "numeric",
      })}
      description={description}
      title={title}
    />,
    { ...size, fonts }
  );
}

import { colors } from "../brand";
import type { DocsOGProps } from "../types";

export function DocsLayout({ title, section, breadcrumb }: DocsOGProps) {
  return (
    <div
      style={{ backgroundColor: colors.background }}
      tw="flex flex-col w-full h-full p-20"
    >
      <div
        style={{ gap: "8px", fontFamily: "PP Neue Montreal" }}
        tw="flex items-center mb-10 text-xl"
      >
        <span style={{ color: colors.foreground }} tw="font-medium">
          Lightfast
        </span>
        <span style={{ color: colors.border }}>/</span>
        <span style={{ color: colors.mutedForeground }} tw="font-normal">
          Docs
        </span>
      </div>

      {(section ?? (breadcrumb && breadcrumb.length > 0)) && (
        <div
          style={{
            gap: "8px",
            fontSize: 18,
            fontFamily: "PP Neue Montreal",
            color: colors.mutedForeground,
          }}
          tw="flex items-center mb-4 font-normal"
        >
          {section && <span>{section}</span>}
          {!section &&
            breadcrumb?.map((crumb, i) => (
              <span key={crumb} style={{ gap: "8px" }} tw="flex items-center">
                {i > 0 && <span style={{ color: colors.border }}>/</span>}
                <span>{crumb}</span>
              </span>
            ))}
        </div>
      )}

      <div tw="flex flex-1 items-center">
        <div
          style={{
            fontSize: 52,
            fontFamily: "PP Neue Montreal",
            color: colors.foreground,
            lineHeight: 1.15,
            letterSpacing: "-0.02em",
          }}
          tw="font-bold"
        >
          {title}
        </div>
      </div>

      <div
        style={{
          fontSize: 18,
          fontFamily: "PP Neue Montreal",
          color: colors.mutedForeground,
        }}
        tw="flex items-center mt-auto font-normal"
      >
        lightfast.ai/docs
      </div>
    </div>
  );
}

import { colors } from "../brand";
import type { ContentOGProps } from "../types";

export function ContentLayout({
  title,
  description,
  category,
  date,
  author,
}: ContentOGProps) {
  return (
    <div
      style={{ backgroundColor: colors.background }}
      tw="flex flex-col w-full h-full p-20"
    >
      <div
        style={{
          fontFamily: "PP Neue Montreal",
          color: colors.foreground,
        }}
        tw="text-xl font-medium mb-10"
      >
        Lightfast
      </div>

      {category && (
        <div tw="flex mb-4">
          <div
            style={{
              fontFamily: "PP Neue Montreal",
              color: colors.brandBlue,
              letterSpacing: "0.05em",
            }}
            tw="text-base font-bold uppercase"
          >
            {category}
          </div>
        </div>
      )}

      <div style={{ gap: "16px" }} tw="flex flex-col flex-1">
        <div
          style={{
            fontFamily: "PP Neue Montreal",
            color: colors.foreground,
            lineHeight: 1.1,
            letterSpacing: "-0.02em",
            overflow: "hidden",
            textOverflow: "ellipsis",
          }}
          tw="text-5xl font-bold"
        >
          {title}
        </div>
        {description && (
          <div
            style={{
              fontSize: 22,
              fontFamily: "PP Neue Montreal",
              color: colors.mutedForeground,
              lineHeight: 1.4,
              overflow: "hidden",
              textOverflow: "ellipsis",
            }}
            tw="font-normal"
          >
            {description}
          </div>
        )}
      </div>

      <div
        style={{
          gap: "16px",
          fontSize: 18,
          fontFamily: "PP Neue Montreal",
          color: colors.mutedForeground,
        }}
        tw="flex items-center mt-auto"
      >
        {author && <span>{author}</span>}
        {author && date && <span style={{ color: colors.border }}>|</span>}
        {date && <span>{date}</span>}
      </div>
    </div>
  );
}

