  const title = page.data.title ?? "Documentation";

  return new ImageResponse(
    <DocsLayout
      breadcrumb={slug.map((s) =>
        s.split("-").map((w) => (w[0]?.toUpperCase() ?? "") + w.slice(1)).join(" ")
      )}
      title={title}
    />,
    { ...size, fonts }
  );
}

export function generateStaticParams() {
  return getPages().map((page) => ({ slug: page.slugs }));
}
```

#### 4. API Reference OG Handler

**File** (new): `apps/www/src/app/(app)/(content)/docs/(api)/api-reference/[[...slug]]/opengraph-image.tsx`

```tsx
import { DocsLayout } from "@repo/og";
import { OG_HEIGHT, OG_WIDTH } from "@repo/og/brand";
import { ImageResponse } from "next/og";
import { getApiPage, getApiPages } from "~/app/(app)/(content)/_lib/source";
import { loadOGFonts } from "~/lib/og-fonts";

export const runtime = "nodejs";
export const alt = "Lightfast API Reference";
export const size = { width: OG_WIDTH, height: OG_HEIGHT };
export const contentType = "image/png";

export default async function Image({
  params,
}: {
  params: Promise<{ slug?: string[] }>;
}) {
  const { slug } = await params;
  const fonts = await loadOGFonts();

  if (!slug || slug.length === 0) {
    return new ImageResponse(
      <DocsLayout section="API Reference" title="API Reference" />,
      { ...size, fonts }
    );
  }

  const page = getApiPage(slug);

  if (!page) {
    return new ImageResponse(<div>Not Found</div>, { ...size });
  }

  const title = page.data.title ?? "API Reference";

  return new ImageResponse(
    <DocsLayout
      section="API Reference"
      title={title}
    />,
    { ...size, fonts }
  );
}

export function generateStaticParams() {
  return getApiPages().map((page) => ({ slug: page.slugs }));
}
```

